// Ambil SEMUA items dari input, bukan hanya first()
const allItems = $input.all();

const analyzed = allItems
  .map(item => item.json)
  .filter(t => t.status === 'analyzed' && t.urgency_level && t.urgency_level !== 'Unknown')
  .slice(0, 10)
  .map(t => ({
    id: t.id,
    title: t.title || '',
    description: t.description ? t.description.substring(0, 200) : '',
    urgency_level: t.urgency_level,
    severity_score: t.severity_score
  }));

// Handle body wrapper dari n8n
const raw = $('Webhook').first().json;
const webhookData = raw.body ? raw.body : raw;

// Format sebagai plain text bukan JSON string — hindari quote conflict
const summaryText = analyzed.length > 0
  ? analyzed.map(t => `ID${t.id}: ${t.title} [${t.urgency_level} score:${t.severity_score}]`).join(' | ')
  : 'No previous tickets found';

return [{
  json: {
    ticket_id: webhookData.ticket_id,
    title: webhookData.title,
    description: webhookData.description,
    recent_tickets: analyzed,
    recent_tickets_summary: summaryText
  }
}];

const response = $input.first().json;
const content = response.choices[0].message.content;
const cleaned = content.replace(/```json|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    detected_language: 'unknown',
    urgency_level: 'Unknown',
    severity_score: 0,
    confidence_score: 0.0,
    reasoning: 'Failed to parse AI response: ' + content,
    similar_ticket_ids: []
  };
}

const contextData = $('Prepare Context').first().json;
const ticket_id = contextData.ticket_id;

const urgency_level = ['Low','Medium','High','Critical'].includes(parsed.urgency_level)
  ? parsed.urgency_level : 'Unknown';
const severity_score = Math.min(100, Math.max(0, parseInt(parsed.severity_score) || 0));
const confidence_score = Math.min(1.0, Math.max(0.0, parseFloat(parsed.confidence_score) || 0.0));
const detected_language = parsed.detected_language || 'unknown';

// Filter similar IDs — harus integer valid & bukan ticket saat ini
const similar_ids = Array.isArray(parsed.similar_ticket_ids)
  ? parsed.similar_ticket_ids
      .map(id => parseInt(id))
      .filter(id => !isNaN(id) && id !== parseInt(ticket_id))
  : [];

return [{
  json: {
    ticket_id,
    urgency_level,
    severity_score,
    confidence_score,
    detected_language,
    reasoning: parsed.reasoning || 'No reasoning provided',
    similar_ticket_ids: JSON.stringify(similar_ids),
    is_critical: urgency_level === 'Critical'
  }
}];

