// Merge escalation note ke data
const analysisData = $('Is Critical?').first().json;
const escalationResponse = $input.first().json;

let escalation_note = '';
try {
  escalation_note = escalationResponse.choices[0].message.content || '';
} catch(e) {
  escalation_note = 'Escalation note generation failed.';
}

return [{
  json: {
    ...analysisData,
    reasoning: analysisData.reasoning + '\n\n[ESCALATION]: ' + escalation_note
  }
}];
